const inp = $input.first().json || {};
var mode = String(inp.mode || 'individuals').trim().toLowerCase();
if (mode !== 'families' && mode !== 'individuals') { mode = 'individuals'; }
var page = parseInt(inp.page, 10); if (!page || page < 1) { page = 1; }
var minP = parseFloat(String(inp.minPremium || '0').replace(/[^0-9.]/g,'')); if (!isFinite(minP)) { minP = 0; }
var proj = JSON.stringify({ name:1, groupName:1, premium:1, sumAssured:1, phoneLast10:1, phone:1 });
return [{ json: { collection: 'clients', mongoQuery: '{}', projection: proj, limit: 100000, mode: mode, page: page, minPremium: minP } }];

const meta = $('Route Seg').first().json;
const rows = $input.all().map(function(i){ return i.json; }).filter(function(j){ return j && Object.keys(j).length>0; });
function num(v){ if(v==null) return 0; var n=parseFloat(String(v).replace(/[^0-9.]/g,'')); return isFinite(n)?n:0; }
var mode = meta.mode;
var groups = {};
rows.forEach(function(r){
  var key;
  if (mode === 'families') { key = (r.groupName && String(r.groupName).trim()) || ('SOLO:' + (r.phoneLast10 || r.name || r._id)); }
  else { key = (r.name ? String(r.name).trim().toLowerCase().replace(/s+/g, ' ') : String(r._id)) + '|' + (r.phoneLast10 || ''); }
  if (!groups[key]) { groups[key] = { members: {}, totalPremium: 0, totalCover: 0, policies: 0, phone: '', label: '' }; }
  var g = groups[key];
  g.totalPremium += num(r.premium);
  g.totalCover += num(r.sumAssured);
  g.policies += 1;
  if (r.name) { g.members[String(r.name).trim()] = true; }
  if (!g.phone && (r.phoneLast10 || r.phone)) { g.phone = r.phoneLast10 || r.phone; }
  if (!g.label && mode === 'families' && r.groupName) { g.label = String(r.groupName); }
  if (!g.label && r.name) { g.label = String(r.name); }
});
var list = Object.keys(groups).map(function(k){ var g=groups[k]; var mem=Object.keys(g.members); return { name: g.label || mem[0] || k, members: mem.length, policies: g.policies, totalPremium: Math.round(g.totalPremium), totalCover: Math.round(g.totalCover), phone: g.phone }; });
if (meta.minPremium > 0) { list = list.filter(function(x){ return x.totalPremium >= meta.minPremium; }); }
list.sort(function(a,b){ return b.totalPremium - a.totalPremium; });
var total = list.length;
var per = 20;
var page = Math.max(1, parseInt(meta.page||1,10)||1);
var pageCount = Math.ceil(total/per)||1;
var pageItems = list.slice((page-1)*per, (page-1)*per+per);
return [{ json: { ok:true, mode: mode, total: total, page: page, pageCount: pageCount, showing: pageItems.length, results: pageItems, hint: 'total ' + total + (mode==='families'?' families':' individuals') + ', sorted by total premium highest first' } }];
